import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { FolderKanban, CheckCircle2, Clock, AlertCircle, Plus, ArrowRight } from 'lucide-react';
import { projectsApi } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { formatRelativeTime, truncate } from '../utils/helpers';

export default function DashboardPage() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [projects, setProjects] = useState([]);
  const [loading, setLoading]   = useState(true);

  useEffect(() => {
    projectsApi.list({ limit: 10 })
      .then(({ data }) => setProjects(data.data || []))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const hour = new Date().getHours();
  const greeting = hour < 12 ? 'Good morning' : hour < 18 ? 'Good afternoon' : 'Good evening';

  return (
    <div>
      {/* Welcome */}
      <div style={{ marginBottom: '2rem' }}>
        <h1 style={{ fontSize: '1.6rem', marginBottom: 4 }}>
          {greeting}, {user?.name?.split(' ')[0]} 👋
        </h1>
        <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>
          Here's what's happening across your projects.
        </p>
      </div>

      {/* Stats */}
      <div className="grid-4" style={{ marginBottom: '2rem' }}>
        {[
          { label: 'Active Projects', value: projects.filter(p => p.status === 'ACTIVE').length, icon: <FolderKanban size={18} />, color: 'var(--accent)' },
          { label: 'Total Projects', value: projects.length, icon: <FolderKanban size={18} />, color: 'var(--purple)' },
          { label: 'Team Members', value: '—', icon: <CheckCircle2 size={18} />, color: 'var(--green)' },
          { label: 'Pending Tasks', value: '—', icon: <Clock size={18} />, color: 'var(--yellow)' },
        ].map((stat) => (
          <div className="stat-card" key={stat.label}>
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '0.75rem' }}>
              <span className="stat-label">{stat.label}</span>
              <span style={{ color: stat.color }}>{stat.icon}</span>
            </div>
            <div className="stat-value">{loading ? '—' : stat.value}</div>
          </div>
        ))}
      </div>

      {/* Projects */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '1rem' }}>
        <h2 style={{ fontSize: '1.1rem' }}>Your Projects</h2>
        <button className="btn btn-primary btn-sm" onClick={() => navigate('/projects')}>
          <Plus size={14} /> New Project
        </button>
      </div>

      {loading ? (
        <div className="empty-state"><div className="spinner spinner-lg" /></div>
      ) : projects.length === 0 ? (
        <div className="empty-state">
          <FolderKanban size={40} />
          <h3>No projects yet</h3>
          <p>Create your first project to get started</p>
          <button className="btn btn-primary" onClick={() => navigate('/projects')}>
            <Plus size={14} /> Create Project
          </button>
        </div>
      ) : (
        <div className="grid-3">
          {projects.map((project) => (
            <div
              key={project._id}
              className="card card-hover"
              style={{ cursor: 'pointer' }}
              onClick={() => navigate(`/projects/${project._id}`)}
            >
              <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', marginBottom: '0.75rem' }}>
                <div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 4 }}>
                    <span style={{
                      fontSize: '0.68rem', fontWeight: 700, letterSpacing: '0.06em',
                      background: 'var(--accent-dim)', color: 'var(--accent)',
                      padding: '1px 6px', borderRadius: 4,
                    }}>{project.key}</span>
                    <span style={{
                      fontSize: '0.68rem', fontWeight: 600,
                      color: project.status === 'ACTIVE' ? 'var(--green)' : 'var(--text-muted)',
                    }}>{project.status}</span>
                  </div>
                  <h3 style={{ fontSize: '0.95rem', fontWeight: 700 }}>{project.name}</h3>
                </div>
                <ArrowRight size={15} style={{ color: 'var(--text-muted)', flexShrink: 0, marginTop: 2 }} />
              </div>

              {project.description && (
                <p style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', marginBottom: '0.75rem', lineHeight: 1.5 }}>
                  {truncate(project.description, 80)}
                </p>
              )}

              <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginTop: 'auto' }}>
                <div className="avatar avatar-sm">{project.owner?.name?.[0]?.toUpperCase()}</div>
                <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>
                  {project.owner?.name} · {formatRelativeTime(project.createdAt)}
                </span>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
